#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int S[N], T[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &S[i], &T[i]);
    }
    int totalS = 0, totalT = 0;
    int maxLead = 0, winner = 0;
    for (int i = 0; i < N; i++) {
        totalS += S[i];
        totalT += T[i];
        int lead;
        if (totalS > totalT) {
            lead = totalS - totalT;
            if (lead > maxLead) {
                maxLead = lead;
                winner = 1;
            }
        } else {
            lead = totalT - totalS;
            if (lead > maxLead) {
                maxLead = lead;
                winner = 2;
            }
        }
    }
    printf("%d %d\n", winner, maxLead);
    return 0;
}

