            T[i] = sc.nextInt();
        }
        int totalS = 0, totalT = 0;
        int maxLead = 0, winner = 0;
        for (int i = 0; i < N; i++) {
            totalS += S[i];
            totalT += T[i];
            int lead;
            if (totalS > totalT) {
                lead = totalS - totalT;
                if (lead > maxLead) {
                    maxLead = lead;
                    winner = 1;
                }
