const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const N = parseInt(lines[idx++]);
const S = [];
const T = [];
for (let i = 0; i < N; i++) {
    const [s, t] = lines[idx++].trim().split(' ').map(Number);
    S.push(s);
    T.push(t);
}
let totalS = 0;
let totalT = 0;
let maxLead = 0;
let winner = 0;
for (let i = 0; i < N; i++) {
    totalS += S[i];
    totalT += T[i];
    const lead = Math.abs(totalS - totalT);
    if (lead > maxLead) {
        maxLead = lead;
        if (totalS > totalT) {
            winner = 1;
        } else {
            winner = 2;
        }
    }
}
console.log(winner + ' ' + maxLead);

